class MockCoreSchema(Mapping[str, Any]):
    """Mocker for `pydantic_core.CoreSchema` which optionally attempts to
    rebuild the thing it's mocking when one of its methods is accessed and raises an error if that fails.
    """

    __slots__ = '_error_message', '_code', '_attempt_rebuild', '_built_memo'

    def __init__(
        self,
        error_message: str,
        *,
        code: PydanticErrorCodes,
        attempt_rebuild: Callable[[], CoreSchema | None] | None = None,
    ) -> None:
        self._error_message = error_message
        self._code: PydanticErrorCodes = code
        self._attempt_rebuild = attempt_rebuild
        self._built_memo: CoreSchema | None = None

    def __getitem__(self, key: str) -> Any:
        return self._get_built().__getitem__(key)

    def __len__(self) -> int:
        return self._get_built().__len__()

    def __iter__(self) -> Iterator[str]:
        return self._get_built().__iter__()

    def _get_built(self) -> CoreSchema:
        if self._built_memo is not None:
            return self._built_memo

        if self._attempt_rebuild:
            schema = self._attempt_rebuild()
            if schema is not None:
                self._built_memo = schema
                return schema
        raise PydanticUserError(self._error_message, code=self._code)

    def rebuild(self) -> CoreSchema | None:
        self._built_memo = None
        if self._attempt_rebuild:
            schema = self._attempt_rebuild()
            if schema is not None:
                return schema
            else:
                raise PydanticUserError(self._error_message, code=self._code)
        return None

class MockCoreSchema(Mapping[str,Any]) {
  __slots__ = '_error_message','_code','_attempt_rebuild','_built_memo'

  __init__(error_message:str, *, code:PydanticErrorCodes, attempt_rebuild:Callable[[],CoreSchema|None]=None) = {
    _error_message=error_message, _code=code, _attempt_rebuild=attempt_rebuild, _built_memo=None
  }

  __getitem__(key)->Any = _get_built().__getitem__(key)
  __len__()->int = _get_built().__len__()
  __iter__()->Iterator[str] = _get_built().__iter__()

  _get_built()->CoreSchema = _built_memo ?? (_attempt_rebuild() ?? !PydanticUserError(_error_message, code=_code))

  rebuild()->CoreSchema|None = _built_memo=None, _attempt_rebuild() ?? !PydanticUserError(_error_message, code=_code) ?? None
}
